  it("allows benign positional text", () => {
    const result = runCli(["Thanks for the clear bug report"]);

    assert.equal(result.status, 0);
    assert.match(result.stdout, /SAFE|clear|No risky content/i);
    assert.equal(result.stderr, "");
  });

